_myself\":\"Got it! We\\u2019ll keep things simple.\",\"steps.site_about.greeting_business\":\"Great! Let\\u2019s set up your business site.\",\"steps.site_about.greeting_client\":\"Nice! Let\\u2019s create something for your client.\",\"steps.site_about.greeting_fallback\":\"Let\\u2019s get started!\",\"steps.experience_level.title\":\"How experienced are you with Elementor?\",\"steps.experience_level.subtitle\":\"This helps us adjust the editor to your workflow.\",\"steps.experience_level.option_beginner\":\"I\\u2019m just getting started\",\"steps.experience_level.option_intermediate\":\"I have some experience\",\"steps.experience_level.option_advanced\":\"I\\u2019m very comfortable with Elementor\",\"steps.theme_selection.title\":\"Start with a theme that fits your needs\",\"steps.theme_selection.subtitle\":\"Hello themes are built to work seamlessly with Elementor.\",\"steps.theme_selection.v2.title\":\"Build faster with Hello Theme\",\"steps.theme_selection.v2.subtitle\":\"Use Elementor\\u2019s lightweight theme for faster setup and full design control.\",\"steps.theme_selection.aria_label\":\"Theme selection\",\"steps.theme_selection.theme_hello_label\":\"Hello\",\"steps.theme_selection.theme_hello_description\":\"A flexible canvas theme you can shape from the ground up\",\"steps.theme_selection.by_elementor\":\"by Elementor\",\"steps.theme_selection.theme_hello_biz_label\":\"Hello Biz\",\"steps.theme_selection.theme_hello_biz_description\":\"A ready-to-start theme with smart layouts and widgets\",\"steps.theme_selection.greeting_beginner\":\"Glad you\\u2019re here!\",\"steps.theme_selection.greeting_default\":\"Great. Let\\u2019s take it to the next step\",\"steps.theme_selection.continue_with_theme\":\"Continue with this theme\",\"steps.theme_selection.v2.continue_with_theme\":\"Continue with Hello\",\"steps.site_features.title\":\"What do you want to include in your site?\",\"steps.site_features.subtitle\":\"We\\u2019ll use this to tailor suggestions for y