INSERT INTO `wp_posts` VALUES (53,1,'2026-07-16 11:37:34','2026-07-16 10:37:34','<img width=\"800\" height=\"192\" src=\"https://uoe-senate-paper-search.local/wp-content/uploads/2026/07/uoelogo.png\" alt=\"\" srcset=\"https://uoe-senate-paper-search.local/wp-content/uploads/2026/07/uoelogo.png 831w, https://uoe-senate-paper-search.local/wp-content/uploads/2026/07/uoelogo-300x72.png 300w, https://uoe-senate-paper-search.local/wp-content/uploads/2026/07/uoelogo-768x184.png 768w\" sizes=\"(max-width: 800px) 100vw, 800px\" />																<h1 data-interaction-id=\"3c7414c\">Senate Paper Search</h1>\n					<h2 data-interaction-id=\"f2325bf\">Search through the papers, agendas and minutes of the University’s Senate and its committees</h2>\n					<h2 data-interaction-id=\"2f7ff17\">Refine Results</h2>\n			<form id=\"filter-1926eda\" action=\"/\" method=\"get\" autocomplete=\"on\">\n			<input type=\"hidden\" name=\"bpf_filter_nonce\" value=\"a9f4fb4e9c\">\n						Document Type\n						<ul>\n							<li>\n								<label for=\"minutes-1926eda\">\n								<input type=\"checkbox\" id=\"minutes-1926eda\" name=\"document-type\" data-taxonomy=\"document-type\" value=\"9\" />\n								Minutes\n								+\n								</label>\n							</li>\n							<li>\n								<label for=\"agenda-papers-1926eda\">\n								<input type=\"checkbox\" id=\"agenda-papers-1926eda\" name=\"document-type\" data-taxonomy=\"document-type\" value=\"8\" />\n								Agenda &amp; Papers\n								+\n								</label>\n							</li>\n						</ul>\n						Committee\n						<ul>\n							<li>\n								<label for=\"senate-1926eda\">\n								<input type=\"checkbox\" id=\"senate-1926eda\" name=\"committee-name\" data-taxonomy=\"committee-name\" value=\"3\" />\n								Senate\n								+\n								</label>\n							</li>\n							<li>\n								<label for=\"sec-1926eda\">\n								<input type=\"checkbox\" id=\"sec-1926eda\" name=\"committee-name\" data-taxonomy=\"committee-name\" value=\"7\" />\n								SEC\n								+\n								</label>\n							</li>\n						</ul>\n						Academic Year\n						<ul>\n								<li>\n									<label for=\"2023/2024-1926eda\">\n										<input type=\"checkbox\" id=\"2023/2024-1926eda\" name=\"academic_year\" data-taxonomy=\"academic_year\" value=\"2023/2024\" />\n										2023/2024\n									</label>\n								</li>\n						</ul>\n						</form>				\n					<h2 data-interaction-id=\"695eea7\">Search Results</h2>\n					<h3 data-interaction-id=\"117d02b\">Sort by date:</h3>\n					<form action=\"/\" method=\"get\" autocomplete=\"on\"><select><option data-order=\"DESC\" data-meta=\"start_date\" value=\"meta_value\">newest first</option><option data-order=\"ASC\" data-meta=\"start_date\" value=\"meta_value\">oldest first</option></select></form>				\n					<article  data-post-id=\"141\" ><a href=\"https://uoe-senate-paper-search.local/paper/test-paper-2/\" ><img src=\"https://uoe-senate-paper-search.local/wp-content/uploads/2026/07/Screenshot-2026-07-16-at-4.34.10-PM.png\" data-bpfwe-src=\"https://uoe-senate-paper-search.local/wp-content/uploads/2026/07/Screenshot-2026-07-16-at-4.34.10-PM.png\" alt=\"Post Image Placeholder\" /></a><h3><a href=\"https://uoe-senate-paper-search.local/paper/test-paper-2/\" >Test paper 2</a></h3><p></p><a href=\"https://uoe-senate-paper-search.local/paper/test-paper-2/\" >Read More »</a><ul><li><a href=\"https://uoe-senate-paper-search.local/committee-name/sec/\">SEC</a></li></ul></article><article  data-post-id=\"34\" ><a href=\"https://uoe-senate-paper-search.local/paper/test-paper/\" ><img width=\"570\" height=\"584\" src=\"https://uoe-senate-paper-search.local/wp-content/uploads/2026/07/Screenshot-2026-07-16-at-4.34.10-PM.png\" alt=\"\" /></a><h3><a href=\"https://uoe-senate-paper-search.local/paper/test-paper/\" >Test paper</a></h3><p></p><a href=\"https://uoe-senate-paper-search.local/paper/test-paper/\" >Read More »</a><ul><li><a href=\"https://uoe-senate-paper-search.local/committee-name/senate/\">Senate</a></li></ul></article>','Home','','publ