arter: Blog Grid','','publish','closed','closed','','card_6a479135a1a81','','','2026-07-17 16:46:30','2026-07-17 15:46:30','view_6a47911f78eb0',0,'https://uoe-senate-paper-search.local/?p=236',0,'avf-post-selection','',0);
INSERT INTO `wp_posts` VALUES (237,1,'2026-07-17 16:46:30','2026-07-17 15:46:30','{\"local_acf_views_view__items\":[{\"local_acf_views_item__group\":\"$post$\",\"local_acf_views_item__field_local_acf_views_field__key\":\"$post$|_post_thumbnail_link\",\"local_acf_views_item__field_local_acf_views_field__image-size\":\"medium\",\"local_acf_views_item__field_local_acf_views_field__id\":\"post-featured-image-link\"},{\"local_acf_views_item__group\":\"$post$\",\"local_acf_views_item__field_local_acf_views_field__key\":\"$post$|_post_title_link\",\"local_acf_views_item__field_local_acf_views_field__id\":\"post-title-link\"},{\"local_acf_views_item__group\":\"$post$\",\"local_acf_views_item__field_local_acf_views_field__key\":\"$post$|_post_excerpt\",\"local_acf_views_item__field_local_acf_views_field__id\":\"post-excerpt\"},{\"local_acf_views_item__group\":\"$post$\",\"local_acf_views_item__field_local_acf_views_field__key\":\"$post$|_post_date\",\"local_acf_views_item__field_local_acf_views_field__label\":\"Published: \",\"local_acf_views_item__field_local_acf_views_field__id\":\"post-date\"}],\"local_acf_views_view__markup\":\"<avf-layout-6a47911f78eb0 class=\\\"{{ _layout.classes }}avf-layout avf-layout--id--{{ _layout.id }} avf-layout--object-id--{{ _layout.object_id }}\\\">\\n\\n\\t{% if post_featured_image_link.value %}\\n\\t\\t<a target=\\\"{{ post_featured_image_link.target }}\\\" class=\\\"avf-layout__post-featured-image-link\\\" href=\\\"{{ post_featured_image_link.href }}\\\">\\n\\t\\t\\t<img class=\\\"avf-layout__post-featured-image-link-image\\\" src=\\\"{{ post_featured_image_link.value }}\\\" width=\\\"{{ post_featured_image_link.width }}\\\" height=\\\"{{ post_featured_image_link.height }}\\\" alt=\\\"{{ post_featured_image_link.alt }}\\\" decoding=\\\"{{ post_featured_image_link.decoding }}\\\" loading=\\\"{{ post_featured_image_link.loading }}\\\" srcset=\\\"{{ post_featured_image_link.srcset }}\\\" sizes=\\\"{{ post_featured_image_link.sizes }}\\\">\\n\\t\\t</a>\\n\\t{% endif %}\\n\\n\\n\\t{% if post_title_link.value %}\\n\\t\\t<a target=\\\"{{ post_title_link.target }}\\\" class=\\\"avf-layout__post-title-link\\\" href=\\\"{{ post_title_link.value }}\\\">\\n\\t\\t\\t{{ post_title_link.linkLabel|default(post_title_link.title) }}\\n\\t\\t</a>\\n\\t{% endif %}\\n\\n\\n\\t{% if post_excerpt.value %}\\n\\t\\t<div class=\\\"avf-layout__post-excerpt\\\">\\n\\t\\t\\t{{ post_excerpt.value }}\\n\\t\\t</div>\\n\\t{% endif %}\\n\\n\\n\\t{% if post_date.value %}\\n\\t\\t<div class=\\\"avf-layout__post-date\\\">\\n\\t\\t\\t<p class=\\\"avf-layout__post-date-label\\\">\\n\\t\\t\\t\\t{{ post_date.label }}\\n\\t\\t\\t</p>\\n\\t\\t\\t<p class=\\\"avf-layout__post-date-field\\\">\\n\\t\\t\\t\\t{{ post_date.value }}\\n\\t\\t\\t</p>\\n\\t\\t</div>\\n\\t{% endif %}\\n\\n</avf-layout-6a47911f78eb0>\\n\",\"local_acf_views_view__css-code\":\"#layout {\\n    display: flex;\\n    flex-direction: column;\\n    padding: 20px;\\n    border: 1px solid #cecece;\\n}\\n\\n#layout__post-title-link {\\n    padding: 20px 0px;\\n}\\n\\n#layout__post-date {\\n    display: flex;\\n    gap: 20px;\\n}\\n\",\"local_acf_views_view__description\":\"A starter Layout for displaying blog post. Visit Post Selections and copy the \\u0027Starter: Blog Grid\\u0027 shortcode into a page to see this Layout in action.\",\"local_acf_views_view__unique-id\":\"view_6a47911f78eb0\",\"local_acf_views_view__title\":\"Starter: Blog Card\"}','Starter: Blog Card','','publish','closed','closed','','view_6a47911f78eb0','','','2026-07-17 16:46:30','2026-07-17 15:46:30','',0,'https://uoe-senate-paper-search.local/?p=237',0,'avf-layout','',0);
